SELECT COUNT(DISTINCT PB.PK) FROM LATTES_PRODBIB PB JOIN LATTES_P_PRODBIB LPP ON LPP.FK_PRODBIB = PB.PK JOIN SERVIDOR S ON S.PK_SIAPE = LPP.FK_SIAPE WHERE LOWER(PB.TIPO) = LOWER('trabalho em evento') AND LOWER(PB.NATUREZA) = LOWER('completo') AND CAST(PB.ANO AS INTEGER) = 2020 AND UPPER(S.SIGLA_CAMPUS) = 'SEN' AND (LOWER(S.AREA_INGRESSO) LIKE LOWER('%letras%') OR LOWER(S.AREA_INGRESSO_OG) LIKE LOWER('%letras%'))